1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Base premium calculation - simplest cases
6	  it("empty item list yields premium of only the 5 G processing fee", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	  it.todo("quote for a single plain sword yields 105 G (100 base + 5 fee)");
14	  it.todo("quote for a single plain amulet yields 65 G (60 base + 5 fee)");
15	  it.todo("quote for a single plain staff yields 85 G (80 base + 5 fee)");
16	  it.todo("quote for a single plain potion yields 45 G (40 base + 5 fee)");
17	  it.todo("quote for a single rune component yields 30 G (25 base + 5 fee)");
18	
19	  // Multiple items
20	  it.todo("quote for two plain swords sums their base premiums");
21	
22	  // Component block discount
23	  it.todo("quote for 2 runes uses 25 G each (no block)");
24	  it.todo("quote for exactly 3 runes uses 60 G block base premium");
25	  it.todo("quote for 4 runes uses 25 G each (block requires exactly 3)");
26	  it.todo("quote for 3 runes + 3 moonstones applies two separate blocks");
27	
28	  // Item-specific modifiers
29	  it.todo("cursed sword adds 50% curse surcharge to that item only");
30	  it.todo("highly enchanted (level >= 5) sword adds 30% surcharge");
31	  it.todo("cursed AND highly enchanted item stacks both surcharges");
32	
33	  // Policy-wide modifiers
34	  it.todo("long-standing customer (>= 2 years) gets 20% loyalty discount");
35	  it.todo("first quote in scenario adds 10% first-insurance surcharge");
36	  it.todo("second quote in scenario gets 15% follow-up contract discount");
37	
38	  // Rounding
39	  it.todo("premium rounds up (in MHPCO's favor)");
40	
41	  // Newcomer integration example: cursed sword -> 165 G
42	  it.todo("newcomer cursed sword integration example yields 165 G");
43	
44	  // Long-standing customer's second contract: 160 G
45	  it.todo("long-standing customer's second contract integration yields 160 G");
46	
47	  // Claims - basic
48	  it.todo("claim with standard damage subtracts 100 G deductible");
49	  it.todo("claim on highly enchanted (>= 8) item reimburses 50% then deductible");
50	  it.todo("claim on dragon-material item gets full reimbursement then deductible");
51	  it.todo("dragon material AND high enchantment - 50% rule wins, then deductible");
52	  it.todo("multiple damage entries each get their own deductible");
53	  it.todo("payout rounds down (in MHPCO's favor)");
54	
55	  // Error/edge cases
56	  it.todo("quote with unknown item type causes error");
57	  it.todo("claim referencing item not in policy causes error");
58	  it.todo("claim with negative damage amount causes error");
59	  it.todo("claim with more damage entries of a type than policy covers causes error");
60	});
61

1	export type Scenario = {
2	  customer: { yearsWithMHPCO: number };
3	  steps: any[];
4	};
5	
6	export type ScenarioResult = {
7	  results: any[];
8	};
9	
10	export const runScenario = (_scenario: Scenario): ScenarioResult => {
11	  return { results: [{ premium: 5 }] };
12	};
